/**
 * Email notification adapter — delivers notifications via email.
 *
 * Features:
 * - Template rendering: generates HTML email bodies based on notification type
 * - Recipient resolution: validates and normalizes email addresses
 * - Pluggable transport: supports swappable email transports (SMTP, in-memory for tests)
 *
 * Architecture: Implements NotificationAdapter interface. Registered with
 * NotificationService via registerAdapter(). All email delivery flows through
 * the EventBus → NotificationService → EmailAdapter pipeline.
 */

import type { NotificationPayload, NotificationType } from '../models/notification.js';
import type { NotificationAdapter } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * A rendered email ready for transport.
 */
export interface RenderedEmail {
  to: string;
  from: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Pluggable transport interface for email delivery.
 * Implement this for SMTP, SES, SendGrid, or testing.
 */
export interface EmailTransport {
  sendMail(email: RenderedEmail): Promise<void>;
}

/**
 * In-memory transport that captures emails for testing.
 */
export class InMemoryTransport implements EmailTransport {
  private sent: RenderedEmail[] = [];

  async sendMail(email: RenderedEmail): Promise<void> {
    this.sent.push(email);
  }

  getSentEmails(): RenderedEmail[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

export interface EmailConfig {
  /** Sender email address */
  from: string;
  /** SMTP host */
  host?: string;
  /** SMTP port */
  port?: number;
  /** Application name used in email templates */
  appName?: string;
  /** Email transport (defaults to InMemoryTransport) */
  transport?: EmailTransport;
}

/**
 * Template definition for a notification type.
 */
interface EmailTemplate {
  subject(payload: NotificationPayload): string;
  html(payload: NotificationPayload): string;
  text(payload: NotificationPayload): string;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Resolve and validate an email recipient address.
 * Normalizes whitespace and converts to lowercase.
 * @throws Error if the address is not a valid email format
 */
export function resolveRecipient(recipient: string): string {
  const normalized = recipient.trim().toLowerCase();
  if (!EMAIL_REGEX.test(normalized)) {
    throw new Error(`Invalid email recipient: ${recipient}`);
  }
  return normalized;
}

/**
 * Render an HTML email template for a given notification type and payload.
 */
function renderTemplate(payload: NotificationPayload, appName: string): EmailTemplate {
  const templates: Record<NotificationType, EmailTemplate> = {
    order_confirmation: {
      subject: (p) => `Order Confirmation: ${p.metadata['orderId'] as string}`,
      html: (p) => {
        const items = p.metadata['items'] as Array<{ name: string; quantity: number; unitPrice: number }> | undefined;
        const total = p.metadata['total'] as number | undefined;
        const itemRows = items
          ? items
              .map(
                (item) =>
                  `<tr><td>${escapeHtml(item.name)}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td></tr>`,
              )
              .join('\n')
          : '';

        return wrapHtml(
          appName,
          `<h2>Thank you for your order!</h2>
<p>Your order <strong>${escapeHtml(String(p.metadata['orderId']))}</strong> has been placed successfully.</p>
<table>
<tr><th>Item</th><th>Qty</th><th>Price</th></tr>
${itemRows}
</table>
<p><strong>Total: $${total !== undefined ? total.toFixed(2) : '0.00'}</strong></p>`,
        );
      },
      text: (p) => p.body,
    },

    order_status_update: {
      subject: (p) => `Order Update: ${p.metadata['orderId'] as string}`,
      html: (p) => {
        const prev = p.metadata['previousStatus'] as string;
        const next = p.metadata['newStatus'] as string;
        return wrapHtml(
          appName,
          `<h2>Order Status Update</h2>
<p>Your order <strong>${escapeHtml(String(p.metadata['orderId']))}</strong> status has changed.</p>
<p>Status: <em>${escapeHtml(prev)}</em> &rarr; <strong>${escapeHtml(next)}</strong></p>`,
        );
      },
      text: (p) => p.body,
    },

    welcome: {
      subject: () => `Welcome to ${appName}!`,
      html: (p) =>
        wrapHtml(
          appName,
          `<h2>Welcome!</h2>
<p>Hi ${escapeHtml(String(p.metadata['userName'] ?? 'there'))},</p>
<p>Welcome to ${escapeHtml(appName)}. We're glad to have you on board.</p>`,
        ),
      text: (p) => p.body,
    },

    account_updated: {
      subject: () => 'Your Account Has Been Updated',
      html: (p) => {
        const changes = p.metadata['changes'] as string[] | undefined;
        const changeList = changes
          ? `<ul>${changes.map((c) => `<li>${escapeHtml(c)}</li>`).join('')}</ul>`
          : '';
        return wrapHtml(
          appName,
          `<h2>Account Updated</h2>
<p>The following changes were made to your account:</p>
${changeList}`,
        );
      },
      text: (p) => p.body,
    },
  };

  return templates[payload.type];
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function wrapHtml(appName: string, content: string): string {
  return `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"><title>${escapeHtml(appName)}</title></head>
<body style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">
${content}
<hr>
<p style="color: #888; font-size: 12px;">&copy; ${escapeHtml(appName)}</p>
</body>
</html>`;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private transport: EmailTransport;
  private appName: string;
  private from: string;

  constructor(private config: EmailConfig) {
    this.from = config.from;
    this.appName = config.appName ?? 'TaskFlow Pro';
    this.transport = config.transport ?? new InMemoryTransport();
  }

  /**
   * Send a notification via email.
   * Resolves the recipient, renders the template, and dispatches via transport.
   * @param payload - The notification to deliver
   * @throws Error if recipient is invalid or transport fails
   */
  async send(payload: NotificationPayload): Promise<void> {
    const to = resolveRecipient(payload.recipient);
    const template = renderTemplate(payload, this.appName);

    const rendered: RenderedEmail = {
      to,
      from: this.from,
      subject: template.subject(payload),
      html: template.html(payload),
      text: template.text(payload),
    };

    await this.transport.sendMail(rendered);
    this.logger.info(`Email sent to ${to}: ${rendered.subject}`);
  }

  /**
   * Get the transport (for testing access to InMemoryTransport).
   */
  getTransport(): EmailTransport {
    return this.transport;
  }

  /**
   * Convenience: get sent emails when using InMemoryTransport.
   * @throws Error if transport is not InMemoryTransport
   */
  getSentEmails(): RenderedEmail[] {
    if (this.transport instanceof InMemoryTransport) {
      return this.transport.getSentEmails();
    }
    throw new Error('getSentEmails() is only available with InMemoryTransport');
  }

  /**
   * Convenience: clear sent emails when using InMemoryTransport.
   */
  clearSentEmails(): void {
    if (this.transport instanceof InMemoryTransport) {
      this.transport.clear();
    }
  }
}

