import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
  resolveRecipient,
} from '../../src/adapters/email.adapter.js';
import type { EmailTransport, RenderedEmail } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    metadata: {
      orderId: 'order-1',
      userId: 'user-1',
      items: [{ name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
    },
    createdAt: new Date('2026-01-15'),
    ...overrides,
  };
}

describe('resolveRecipient', () => {
  it('should normalize email to lowercase and trim', () => {
    expect(resolveRecipient('  Alice@Example.COM  ')).toBe('alice@example.com');
  });

  it('should accept valid email addresses', () => {
    expect(resolveRecipient('user@domain.co')).toBe('user@domain.co');
    expect(resolveRecipient('first.last@company.org')).toBe('first.last@company.org');
  });

  it('should reject addresses without @', () => {
    expect(() => resolveRecipient('not-an-email')).toThrow('Invalid email recipient');
  });

  it('should reject empty strings', () => {
    expect(() => resolveRecipient('')).toThrow('Invalid email recipient');
  });

  it('should reject addresses without domain', () => {
    expect(() => resolveRecipient('user@')).toThrow('Invalid email recipient');
  });

  it('should reject addresses without local part', () => {
    expect(() => resolveRecipient('@domain.com')).toThrow('Invalid email recipient');
  });
});

describe('InMemoryTransport', () => {
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
  });

  it('should capture sent emails', async () => {
    const email: RenderedEmail = {
      to: 'alice@example.com',
      from: 'noreply@taskflow.com',
      subject: 'Test',
      html: '<p>Hello</p>',
      text: 'Hello',
    };

    await transport.sendMail(email);

    expect(transport.getSentEmails()).toHaveLength(1);
    expect(transport.getSentEmails()[0]).toEqual(email);
  });

  it('should clear sent emails', async () => {
    await transport.sendMail({
      to: 'a@b.com',
      from: 'x@y.com',
      subject: 's',
      html: '',
      text: '',
    });

    transport.clear();
    expect(transport.getSentEmails()).toHaveLength(0);
  });
});

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
    adapter = new EmailAdapter({
      from: 'noreply@taskflow.com',
      appName: 'TaskFlow Pro',
      transport,
    });
  });

  describe('send', () => {
    it('should render and send order_confirmation email', async () => {
      const payload = makePayload();

      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.from).toBe('noreply@taskflow.com');
      expect(emails[0]?.subject).toBe('Order Confirmation: order-1');
      expect(emails[0]?.html).toContain('Thank you for your order');
      expect(emails[0]?.html).toContain('Widget');
      expect(emails[0]?.html).toContain('$20.00');
      expect(emails[0]?.html).toContain('order-1');
      expect(emails[0]?.text).toContain('Widget x2');
    });

    it('should render order_status_update email', async () => {
      const payload = makePayload({
        type: 'order_status_update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
        metadata: {
          orderId: 'order-1',
          previousStatus: 'pending',
          newStatus: 'confirmed',
        },
      });

      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails[0]?.subject).toBe('Order Update: order-1');
      expect(emails[0]?.html).toContain('Order Status Update');
      expect(emails[0]?.html).toContain('pending');
      expect(emails[0]?.html).toContain('confirmed');
    });

    it('should render welcome email', async () => {
      const payload = makePayload({
        type: 'welcome',
        subject: 'Welcome to TaskFlow Pro!',
        body: 'Welcome to TaskFlow Pro.',
        metadata: { userName: 'Alice' },
      });

      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails[0]?.subject).toBe('Welcome to TaskFlow Pro!');
      expect(emails[0]?.html).toContain('Welcome!');
      expect(emails[0]?.html).toContain('Alice');
    });

    it('should render account_updated email with changes list', async () => {
      const payload = makePayload({
        type: 'account_updated',
        subject: 'Your Account Has Been Updated',
        body: 'Your account has been updated.',
        metadata: { changes: ['email', 'name'] },
      });

      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails[0]?.subject).toBe('Your Account Has Been Updated');
      expect(emails[0]?.html).toContain('Account Updated');
      expect(emails[0]?.html).toContain('email');
      expect(emails[0]?.html).toContain('name');
    });

    it('should normalize recipient email', async () => {
      const payload = makePayload({ recipient: '  ALICE@Example.COM  ' });

      await adapter.send(payload);

      expect(transport.getSentEmails()[0]?.to).toBe('alice@example.com');
    });

    it('should throw on invalid recipient', async () => {
      const payload = makePayload({ recipient: 'not-an-email' });

      await expect(adapter.send(payload)).rejects.toThrow('Invalid email recipient');
    });

    it('should wrap HTML content with DOCTYPE and layout', async () => {
      const payload = makePayload();

      await adapter.send(payload);

      const html = transport.getSentEmails()[0]?.html ?? '';
      expect(html).toContain('<!DOCTYPE html>');
      expect(html).toContain('<html>');
      expect(html).toContain('TaskFlow Pro');
    });

    it('should escape HTML in dynamic content', async () => {
      const payload = makePayload({
        type: 'welcome',
        metadata: { userName: '<script>alert("xss")</script>' },
      });

      await adapter.send(payload);

      const html = transport.getSentEmails()[0]?.html ?? '';
      expect(html).not.toContain('<script>');
      expect(html).toContain('&lt;script&gt;');
    });
  });

  describe('custom transport', () => {
    it('should use provided transport', async () => {
      const sent: RenderedEmail[] = [];
      const customTransport: EmailTransport = {
        sendMail: async (email) => {
          sent.push(email);
        },
      };

      const customAdapter = new EmailAdapter({
        from: 'test@example.com',
        transport: customTransport,
      });

      await customAdapter.send(makePayload());
      expect(sent).toHaveLength(1);
    });

    it('should propagate transport errors', async () => {
      const failingTransport: EmailTransport = {
        sendMail: async () => {
          throw new Error('SMTP connection refused');
        },
      };

      const failAdapter = new EmailAdapter({
        from: 'test@example.com',
        transport: failingTransport,
      });

      await expect(failAdapter.send(makePayload())).rejects.toThrow('SMTP connection refused');
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should return sent emails from InMemoryTransport', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should throw getSentEmails if not using InMemoryTransport', () => {
      const customAdapter = new EmailAdapter({
        from: 'test@example.com',
        transport: { sendMail: async () => {} },
      });

      expect(() => customAdapter.getSentEmails()).toThrow(
        'getSentEmails() is only available with InMemoryTransport',
      );
    });
  });

  describe('defaults', () => {
    it('should default appName to TaskFlow Pro', async () => {
      const defaultAdapter = new EmailAdapter({
        from: 'test@example.com',
        transport,
      });

      await defaultAdapter.send(
        makePayload({ type: 'welcome', metadata: { userName: 'Bob' } }),
      );

      expect(transport.getSentEmails()[0]?.subject).toBe('Welcome to TaskFlow Pro!');
    });

    it('should use InMemoryTransport by default', () => {
      const defaultAdapter = new EmailAdapter({ from: 'test@example.com' });
      expect(defaultAdapter.getTransport()).toBeInstanceOf(InMemoryTransport);
    });
  });
});
